directive.example:
NoJS.directive('tooltip', {
  init(el, attrName, value) {
    el.title = value;
    el.style.cursor = 'help';
  }
});

interceptor.example:
NoJS.interceptor('request', (url, opts) => {
  opts.headers['Authorization'] = 'Bearer ' + token;
  return opts;
});

use.example:
NoJS.use({
  name: 'auth',
  install(NoJS, options) {
    NoJS.interceptor('request', (url, opts) => {
      opts.headers['Authorization'] = 'Bearer ' + token;
      return opts;
    });
  }
});
